Implementasi deteksi siklus pada directed graph menggunakan Depth First Search (DFS). Metode ini efisien (O(V + E)) dan krusial untuk mencegah infinite loop pada resolusi dependensi atau workflow automation.

```python
from typing import Dict, List, Set

def has_cycle(graph: Dict[int, List[int]]) -> bool:
    """
    Detects cycle in a directed graph using DFS.
    Returns True if cycle exists, False otherwise.
    """
    visited: Set[int] = set()
    rec_stack: Set[int] = set()

    def dfs(node: int) -> bool:
        visited.add(node)
        rec_stack.add(node)

        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                if dfs(neighbor):
                    return True
            elif neighbor in rec_stack:
                # Cycle detected: neighbor is in current recursion stack
                return True

        rec_stack.remove(node)
        return False

    for node in graph:
        if node not in visited:
            if dfs(node):
                return True

    return False

